module top_module(reset_clk, rst, inp, out);(* bus_width *)
  parameter WIDTH = 2;

  (* an_attribute_on_localparam = 55 *)
  localparam INCREMENT = 5;

  input  wire reset_clk;
  input  wire rst;
  input  wire [WIDTH-1:0] inp;
  output reg  [WIDTH-1:0] out;

  always @(posedge reset_clk)
    if (rst) out <= 0;
    else     out <= inp + INCREMENT;

endmodule
